import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Edit3, Save, Plus, Trash2, MapPin, ShieldCheck } from 'lucide-react';

export default function Profile() {
  const [isEdit, setIsEdit] = useState(false);
  const [name, setName] = useState("Arjun Das");
  const [skills, setSkills] = useState(["Web Design", "Gardening", "Plumbing"]);

  return (
    <div className="p-10 max-w-5xl mx-auto space-y-8">
      <div className="bg-white rounded-[40px] p-10 shadow-sm border border-slate-50 flex items-center gap-10">
        <div className="w-32 h-32 bg-teal-50 rounded-full flex items-center justify-center text-teal-600 text-4xl font-black border-4 border-white shadow-xl">{name[0]}</div>
        <div className="flex-1">
          {isEdit ? <input value={name} onChange={e => setName(e.target.value)} className="text-4xl font-black text-slate-900 bg-slate-50 px-4 py-1 rounded-xl outline-none ring-2 ring-teal-500" /> : <h1 className="text-4xl font-black text-slate-900">{name}</h1>}
          <p className="text-slate-400 font-bold mt-2 flex items-center gap-2"><MapPin size={18} className="text-teal-600"/> Kadavanthra, Kochi</p>
        </div>
        <button onClick={() => setIsEdit(!isEdit)} className={`flex items-center gap-2 px-8 py-4 rounded-2xl font-bold transition-all ${isEdit ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-600'}`}>{isEdit ? <><Save size={20}/> Save Profile</> : <><Edit3 size={20}/> Edit Profile</>}</button>
      </div>

      <div className="bg-white rounded-[40px] p-10 border border-slate-50">
        <h3 className="text-xl font-black mb-8">Skill Preferences</h3>
        <div className="flex flex-wrap gap-3">
          {skills.map(s => (
            <div key={s} className="px-6 py-3 bg-teal-50 text-teal-700 rounded-2xl font-bold text-sm flex items-center gap-2">
              {s} {isEdit && <Trash2 size={14} className="cursor-pointer text-red-400" onClick={() => setSkills(skills.filter(i => i !== s))}/>}
            </div>
          ))}
          {isEdit && <button onClick={() => setSkills([...skills, "New Skill"])} className="p-3 bg-slate-900 text-white rounded-2xl"><Plus size={20}/></button>}
        </div>
      </div>
    </div>
  );
}
